import type { ComponentPropsWithRef, ReactNode } from 'react';
import { cx } from '@/utils/cx';

interface RootProps extends ComponentPropsWithRef<'div'> {
  /** Card variant style */
  variant?: 'default' | 'bordered' | 'shadow';
  /** Card size */
  size?: 'sm' | 'md' | 'lg';
  /** Card color */
  color?: 'default' | 'secondary';
}

const Root = ({
  variant = 'bordered',
  size = 'md',
  color = 'default',
  className,
  ...props
}: RootProps) => {
  return (
    <div
      {...props}
      className={cx(
        // Base styles
        'overflow-hidden rounded-xl',
        color === 'default' && 'bg-primary',
        color === 'secondary' && 'bg-secondary',
        // Variant styles
        variant === 'default' && 'shadow-xs',
        variant === 'bordered' && 'ring-1 ring-secondary',
        variant === 'shadow' && 'shadow-lg',
        // Size styles
        size === 'sm' && 'rounded-lg',
        size === 'md' && 'rounded-xl',
        size === 'lg' && 'rounded-2xl',
        className,
      )}
    />
  );
};

const Header = ({
  className,
  variant,
  ...props
}: ComponentPropsWithRef<'div'> & { variant?: 'default' | 'secondary' }) => {
  return (
    <div
      {...props}
      className={cx(
        cx(
          'p-4',
          variant !== 'secondary' && ['border-b border-secondary bg-primary'],
          className,
        ),
      )}
    />
  );
};

const Body = ({ className, ...props }: ComponentPropsWithRef<'div'>) => {
  return (
    <div
      {...props}
      className={cx('flex flex-col px-4 py-2 gap-2', className)}
    />
  );
};

const Footer = ({ className, ...props }: ComponentPropsWithRef<'div'>) => {
  return (
    <div
      {...props}
      className={cx(
        'border-t border-secondary bg-utility-gray-50 px-6 py-4',
        className,
      )}
    />
  );
};

interface CardGridProps {
  /**
   * The cards to display in the grid
   */
  children: ReactNode;
  /**
   * Additional CSS classes
   */
  className?: string;
  /**
   * The title of the grid
   */
  title?: string;
  /**
   * The subtitle of the grid
   */
  subtitle?: string;
}

export const Grid = ({
  title = undefined,
  subtitle = undefined,
  children,
  className = '',
}: CardGridProps) => {
  return (
    <div className={cx('flex flex-wrap gap-4', className)}>
      {title && (
        <div className="flex flex-col items-start w-full gap-1">
          <div className="text-lg">{title}</div>
          {subtitle && (
            <div className="text-sm font-inter text-default-400">
              {subtitle}
            </div>
          )}
        </div>
      )}
      {children}
    </div>
  );
};

const Card = Root as typeof Root & {
  Header: typeof Header;
  Body: typeof Body;
  Footer: typeof Footer;
  Grid: typeof Grid;
};

Card.Header = Header;
Card.Body = Body;
Card.Footer = Footer;
Card.Grid = Grid;

export { Card };
